SQLLite.SQL:

UPDATE PAYMENTS P
SET P.RECEIPT_REQUIRED = ${param.receiptRequiredFlag}
WHERE	P.CREATED_BY = ${param.inputBy} 
AND TRUNC(P.DATE_ENTERED) = TRUNC(TO_DATE(${param.dateCreated}, 'DD-MM-YYYY'))
AND P.ADMIN_COURT_CODE = ${param.courtId}
AND P.COUNTER_PAYMENT = 'N'
AND P.RECEIPT_REQUIRED = 'Y'
